const raw = $input.first().json.content[0].text;
const article = JSON.parse(raw);

const today = new Date().toISOString().slice(0, 10);
const tagsYaml = article.tags.map((t) => `"${t}"`).join(", ");

const frontmatter = `---\ntitle: "${article.title.replace(/"/g, '\\"')}"\ndescription: "${article.description.replace(/"/g, '\\"')}"\ndate: "${today}"\ntags: [${tagsYaml}]\n---\n\n`;

return [{
  json: {
    slug: article.slug,
    title: article.title,
    path: `content/blog/${article.slug}.md`,
    message: `Add article: ${article.title} (auto-generated)`,
    fileContent: frontmatter + article.body_markdown,
  },
}];
